import React, { useState, useEffect } from 'react';
import axios from 'axios';
import SearchBar from '../components/SearchBar';
import Filters from '../components/Filters';
import ServiceCard from '../components/ServiceCard';

const Home = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [results, setResults] = useState([]);
  const [searched, setSearched] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [currentLocation, setCurrentLocation] = useState(null);

  // The backend API base URL
  // Assuming it runs on localhost:5000 or similar
  const API_BASE_URL = 'http://localhost:5000/api';

  const handleSearch = async (pincode) => {
    setLoading(true);
    setError(null);
    setSearched(true);

    try {
      // 1. Get coordinates for the pincode
      // Using a try-catch for the geocoding step specifically
      let lat, lng;
      try {
        const geoResponse = await axios.get(`${API_BASE_URL}/pincode/${pincode}`);
        lat = geoResponse.data.lat;
        lng = geoResponse.data.lng;
        setCurrentLocation({ lat, lng, pincode });
      } catch (err) {
        throw new Error('Could not find location for this pincode. Please try a different one.');
      }

      // 2. Fetch nearby services
      fetchServices(lat, lng, selectedCategory);

    } catch (err) {
      setError(err.message || 'An error occurred while fetching data');
      setResults([]);
      setLoading(false);
    }
  };

  const fetchServices = async (lat, lng, category) => {
    setLoading(true);
    setError(null);

    try {
      // Build query string
      let url = `${API_BASE_URL}/nearby?lat=${lat}&lng=${lng}&radius=5`;
      if (category !== 'all') {
        url += `&type=${category}`;
      }

      const response = await axios.get(url);

      // Sort results by nearest distance
      const sortedResults = response.data.sort((a, b) => a.distance - b.distance);
      setResults(sortedResults);

    } catch (err) {
      setError('Failed to fetch nearby services. The server might be unreachable.');
      setResults([]);
    } finally {
      setLoading(false);
    }
  };

  // Re-fetch when category changes but we already have a location
  useEffect(() => {
    if (currentLocation && !loading) {
      fetchServices(currentLocation.lat, currentLocation.lng, selectedCategory);
    }
  }, [selectedCategory]);

  return (
    <div className="container">
      <header className="header">
        <h1>Animal Helper</h1>
        <p>Find nearby veterinary clinics, hospitals, and pet services instantly</p>
      </header>

      <main>
        <SearchBar onSearch={handleSearch} loading={loading} />

        {searched && (
          <Filters 
            selectedCategory={selectedCategory} 
            onSelectCategory={setSelectedCategory} 
          />
        )}

        <section className="results-section">
          {loading && (
            <div className="loading-state">
              <div className="loading-spinner"></div>
              <p className="state-title">Finding nearby services...</p>
              <p className="state-desc">Searching within a 5km radius</p>
            </div>
          )}

          {error && !loading && (
            <div className="error-state">
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#EF4444" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{margin: '0 auto 1rem auto'}}>
                <circle cx="12" cy="12" r="10"></circle>
                <line x1="12" y1="8" x2="12" y2="12"></line>
                <line x1="12" y1="16" x2="12.01" y2="16"></line>
              </svg>
              <p className="state-title">Oops! Something went wrong</p>
              <p className="state-desc">{error}</p>
            </div>
          )}

          {!loading && !error && searched && results.length === 0 && (
            <div className="empty-state">
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#6B7280" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{margin: '0 auto 1rem auto'}}>
                <circle cx="11" cy="11" r="8"></circle>
                <line x1="21" y1="21" x2="16.65" y2="16.65"></line>
              </svg>
              <p className="state-title">No services found</p>
              <p className="state-desc">We couldn't find any {selectedCategory !== 'all' ? selectedCategory.replace('_', ' ') : ''} services within 5km of {currentLocation?.pincode}.</p>
            </div>
          )}

          {!loading && !error && results.length > 0 && (
            <>
              <div className="results-header">
                <h2 className="results-title">Nearby Services</h2>
                <span className="results-count">{results.length} found</span>
              </div>
              <div className="results-grid">
                {results.map((service) => (
                  <ServiceCard key={service.id || service._id || Math.random()} service={service} />
                ))}
              </div>
            </>
          )}
        </section>
      </main>
    </div>
  );
};

export default Home;
